using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketsController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<object> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        return Ok(new
        {
            prediction.Category,
            Confidence = prediction.Score.Max(),
            Scores = new
            {
                Billing = prediction.Score.ElementAtOrDefault(0),
                General = prediction.Score.ElementAtOrDefault(1),
                Technical = prediction.Score.ElementAtOrDefault(2),
            },
        });
    }
}

arguments.new_str:
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly string[] _labels;

    public TicketsController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;

        // Extract label names from the model's output schema
        var engine = predictionPool.GetPredictionEngine();
        var labelColumn = engine.OutputSchema.GetColumnOrNull("Score");
        if (labelColumn.HasValue)
        {
            var slotNames = new VBuffer<ReadOnlyMemory<char>>();
            labelColumn.Value.GetSlotNames(ref slotNames);
            _labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        }
        else
        {
            _labels = ["Billing", "General", "Technical"];
        }
    }

    [HttpPost("classify")]
    public ActionResult<object> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        var scores = _labels
            .Zip(prediction.Score, (label, score) => new { label, score })
            .ToDictionary(x => x.label, x => x.score);

        return Ok(new
        {
            prediction.Category,
            Confidence = prediction.Score.Max(),
            Scores = scores,
        });
    }
}

